import{_ as e,o as d,c as a,a2 as i}from"./chunks/framework.CZqXuAiL.js";const b=JSON.parse('{"title":"Mitigation Overview","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/mitigation/overview.md","filePath":"openshield-xdp/mitigation/overview.md","lastUpdated":1782454750000}'),r={name:"openshield-xdp/mitigation/overview.md"};function o(s,t,n,l,h,c){return d(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="mitigation-overview" tabindex="-1">Mitigation Overview <a class="header-anchor" href="#mitigation-overview" aria-label="Permalink to &quot;Mitigation Overview&quot;">​</a></h1><p>When an IP&#39;s suspicion score reaches the effective threshold, OpenShield automatically bans it. Multiple escalation mechanisms tighten response for repeat offenders and subnet-level attacks.</p><h2 id="ban-types" tabindex="-1">Ban types <a class="header-anchor" href="#ban-types" aria-label="Permalink to &quot;Ban types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Mechanism</th><th>Duration</th></tr></thead><tbody><tr><td>Single-IP</td><td>Inserted when suspicion ≥ threshold</td><td><code>ban_duration</code> (default 1 hour)</td></tr><tr><td>LPM subnet</td><td>CIDR-level via longest-prefix-match trie</td><td><code>subnet_ban_duration</code> (default 2 hours)</td></tr><tr><td>Auto /24 escalation</td><td>After N single-IP bans per /24</td><td><code>ban_duration * 2</code></td></tr><tr><td>Star (repeat)</td><td>6 offence levels, multipliers ×1–×32</td><td><code>ban_duration * star_multiplier</code></td></tr></tbody></table><h2 id="ban-reason-codes" tabindex="-1">Ban reason codes <a class="header-anchor" href="#ban-reason-codes" aria-label="Permalink to &quot;Ban reason codes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Code</th><th>Trigger</th></tr></thead><tbody><tr><td>1</td><td>PPS threshold exceeded</td></tr><tr><td>2</td><td>BPS threshold exceeded</td></tr><tr><td>3</td><td>TCP PPS exceeded</td></tr><tr><td>4</td><td>UDP PPS exceeded</td></tr><tr><td>5</td><td>ICMP PPS exceeded</td></tr><tr><td>6</td><td>SYN PPS exceeded</td></tr><tr><td>7</td><td>New source flood</td></tr><tr><td>8</td><td>Bogus TCP flags</td></tr><tr><td>9</td><td>Connection rate limit</td></tr><tr><td>10</td><td>TTL anomaly</td></tr><tr><td>11</td><td>Packet size anomaly</td></tr><tr><td>12</td><td>Entropy spoofing</td></tr><tr><td>13</td><td>SYN/FIN ratio</td></tr></tbody></table><h2 id="effective-threshold" tabindex="-1">Effective threshold <a class="header-anchor" href="#effective-threshold" aria-label="Permalink to &quot;Effective threshold&quot;">​</a></h2><p>Repeat offenders face a stricter threshold:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>effective = suspicion_threshold * 2 / (2 + ban_count)</span></span>
<span class="line"><span>Minimum floor = 10</span></span></code></pre></div><p>First offence: full threshold (default 100). After 3 bans: threshold drops to 40.</p><h2 id="rate-limiting-modes" tabindex="-1">Rate limiting modes <a class="header-anchor" href="#rate-limiting-modes" aria-label="Permalink to &quot;Rate limiting modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Config</th><th>Behaviour</th></tr></thead><tbody><tr><td>Threshold scoring</td><td><code>rate_limit_mode: threshold</code></td><td>Additive suspicion per violation. Cumulative ban</td></tr><tr><td>Token bucket</td><td><code>rate_limit_mode: token_bucket</code></td><td>Per-IP token bucket with <code>token_rate</code> and <code>token_burst</code></td></tr></tbody></table><h2 id="whitelist" tabindex="-1">Whitelist <a class="header-anchor" href="#whitelist" aria-label="Permalink to &quot;Whitelist&quot;">​</a></h2><p>Per-IP flags with granular bypass:</p><table tabindex="0"><thead><tr><th>Flag</th><th>Effect</th></tr></thead><tbody><tr><td>Full bypass (0x0000)</td><td>Skip all checks</td></tr><tr><td>Skip ban (0x0001)</td><td>Skip ban + subnet ban</td></tr><tr><td>Skip rate (0x0002)</td><td>Skip rate threshold</td></tr><tr><td>Skip validation (0x0004)</td><td>Skip private/bogon/bogus TCP</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Empty-map fast path</p><p>When 0 whitelist entries exist, the whitelist lookup is skipped entirely. Same for bans. Updated automatically after every config change.</p></div><h2 id="related-pages" tabindex="-1">Related pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related pages&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/mitigation/bans">Ban System</a> · <a href="/pingless-studios-docs/openshield-xdp/mitigation/rate-limiting">Rate Limiting</a> · <a href="/pingless-studios-docs/openshield-xdp/detection-engine/overview">Detection Overview</a></p>`,18)])])}const u=e(r,[["render",o]]);export{b as __pageData,u as default};
